.html-wrap table {
	width: 100%;
	border-collapse: collapse;
	margin: 0.5rem 0 1rem;
	font-size: 0.95rem;
}

.html-wrap th,
.html-wrap td {
	text-align: left;
	padding: 0.5rem 0.65rem;
	border-bottom: 1px solid rgba(111, 198, 255, 0.22);
}

.html-wrap thead th {
	border-bottom-color: rgba(111, 198, 255, 0.5);
	color: #eef7ff;
}

.html-wrap tbody tr:nth-child(odd) {
	background: rgba(11, 28, 46, 0.35);
}
